using Payments;

namespace Payments.Tests;

[TestClass]
public class PaymentGatewayChargeTests
{
    private PaymentGateway _gateway = null!;

    [TestInitialize]
    public void Setup()
    {
        _gateway = new PaymentGateway();
    }

    // ── ChargeAsync – happy path ──────────────────────────────────────

    [TestMethod]
    public async Task ChargeAsync_ValidTokenAndAmount_ReturnsSuccess()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 50.00m);

        Assert.IsTrue(result.Success);
        Assert.IsFalse(string.IsNullOrWhiteSpace(result.ChargeId));
    }

    [TestMethod]
    public async Task ChargeAsync_MinimumAmount_ReturnsSuccess()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 0.01m);

        Assert.IsTrue(result.Success);
    }

    [TestMethod]
    public async Task ChargeAsync_LargeAmount_ReturnsSuccess()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 999_999.99m);

        Assert.IsTrue(result.Success);
    }

    [TestMethod]
    public async Task ChargeAsync_SuccessfulCharge_ReturnsUniqueChargeId()
    {
        var result1 = await _gateway.ChargeAsync("tok_visa_1", 10.00m);
        var result2 = await _gateway.ChargeAsync("tok_visa_2", 20.00m);

        Assert.AreNotEqual(result1.ChargeId, result2.ChargeId);
    }

    // ── ChargeAsync – input validation ────────────────────────────────

    [TestMethod]
    public async Task ChargeAsync_NullToken_ThrowsArgumentException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.ChargeAsync(null!, 10.00m));
    }

    [TestMethod]
    public async Task ChargeAsync_EmptyToken_ThrowsArgumentException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.ChargeAsync(string.Empty, 10.00m));
    }

    [TestMethod]
    public async Task ChargeAsync_WhitespaceToken_ThrowsArgumentException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.ChargeAsync("   ", 10.00m));
    }

    [TestMethod]
    public async Task ChargeAsync_ZeroAmount_ThrowsArgumentOutOfRangeException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentOutOfRangeException>(
            () => _gateway.ChargeAsync("tok_valid", 0m));
    }

    [TestMethod]
    public async Task ChargeAsync_NegativeAmount_ThrowsArgumentOutOfRangeException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentOutOfRangeException>(
            () => _gateway.ChargeAsync("tok_valid", -5.00m));
    }

    // ── ChargeAsync – failure scenarios ───────────────────────────────

    [TestMethod]
    public async Task ChargeAsync_DeclinedCard_ReturnsFailure()
    {
        var result = await _gateway.ChargeAsync("tok_declined", 50.00m);

        Assert.IsFalse(result.Success);
    }
}

